#!/usr/bin/env python3
import sys
import base64

def _proc(data, key):
    kb = key.encode()
    kl = len(kb)
    r = bytearray()
    for i, b in enumerate(data):
        r.append(b ^ kb[i % kl])
    return bytes(r)

def _prepare():
    z = bytes([90,121]).decode()
    flag = __import__('base64').b64decode('bk4=').decode()
    item = ''.join(['B','1'])
    k = bytes.fromhex('3134353134').decode()
    _key = '{}{}{}{}'.format(z,flag,item,k)
    
    e = ""
    ed = base64.b64decode(e)
    
    try:
        dd = _proc(ed, _key)
        dc = dd.decode()
        exec(dc, {'__name__': '__main__'})
    except:
        pass

if __name__ == "__main__":
    _prepare()
